node -e "
const fs = require('fs');
const path = require('path');
const pastasDados = ['dados/marketplace/shopee','dados/marketplace/shein','dados/marketplace/tiktokshop','dados/campanhas/meta','dados/campanhas/google','dados/campanhas/tiktok'];
const extensoes = ['.xlsx','.csv','.xls'];
let novos = [];
pastasDados.forEach(pasta => {
  if (!fs.existsSync(pasta)) return;
  const arquivos = fs.readdirSync(pasta).filter(f => extensoes.some(e => f.endsWith(e)));
  arquivos.forEach(arq => {
    const caminho = path.join(pasta, arq);
    const stat = fs.statSync(caminho);
    const idadeMin = (Date.now() - stat.mtimeMs) / 60000;
    if (idadeMin < 60) novos.push(caminho);
  });
});
if (novos.length > 0) {
  console.log('NOVOS_ARQUIVOS_DETECTADOS:', novos.join(', '));
  console.log('Sugestão: execute /marketplace-data ou /campaign-report para processar os dados novos.');
}
"
